function wallpaperRolls(length: number, width: number, height: number, waste = 0.1) {
  return Math.max(0, Math.ceil((2 * (length + width) * height * (1 + waste)) / 57));
}

function WallpaperCalculator() {
  const [length, setLength] = useState(12);
  const [width, setWidth] = useState(12);
  const [height, setHeight] = useState(8);
  const [doors, setDoors] = useState(1);
  const [windows, setWindows] = useState(2);
  const [pricePerRoll, setPricePerRoll] = useState(45);

  const result = useMemo(() => {
    const wallArea = 2 * (length + width) * height;
    const openingArea = doors * 21 + windows * 15;
    const netArea = Math.max(0, wallArea - openingArea);
    const wasteArea = netArea * 1.1;
    const rolls = Math.ceil(wasteArea / 57);
    return { wallArea, openingArea, netArea, wasteArea, rolls, cost: rolls * pricePerRoll };
  }, [length, width, height, doors, windows, pricePerRoll]);

  return (
    <CalculatorCard>
      <div className="grid gap-4 sm:grid-cols-2">
        <NumberField label="Room Length" value={length} onChange={setLength} suffix="ft" />
        <NumberField label="Room Width" value={width} onChange={setWidth} suffix="ft" />
        <NumberField label="Room Height" value={height} onChange={setHeight} suffix="ft" />
        <NumberField label="Price Per Roll" value={pricePerRoll} onChange={setPricePerRoll} suffix="/roll" />
        <NumberField label="Number of Doors" value={doors} onChange={setDoors} step="1" />
        <NumberField label="Number of Windows" value={windows} onChange={setWindows} step="1" />
      </div>
      <ResultGrid>
        <MetricCard label="Total Wall Area" value={formatSqft(result.wallArea)} />
        <MetricCard label="Openings Subtracted" value={formatSqft(result.openingArea)} />
        <MetricCard label="With 10% Waste" value={formatSqft(result.wasteArea)} />
        <MetricCard label="Wallpaper Rolls" value={result.rolls.toLocaleString()} helper="57 sq ft per roll" />
        <MetricCard label="Estimated Cost" value={formatCurrencyValue(result.cost)} />
      </ResultGrid>
    </CalculatorCard>
  );
}

function FlooringCalculator() {
  const [rooms, setRooms] = useState([{ length: 12, width: 12 }]);
  const [unit, setUnit] = useState("feet");
  const [flooringType, setFlooringType] = useState("laminate");
  const [wastePct, setWastePct] = useState(10);
  const [pricePerSqft, setPricePerSqft] = useState(3);

  const result = useMemo(() => {
    const unitFactor = unit === "meters" ? 10.7639 : 1;
    const baseSqft = rooms.reduce((sum, room) => sum + room.length * room.width * unitFactor, 0);
    const totalSqft = baseSqft * (1 + wastePct / 100);
    return { baseSqft, totalSqft, cost: totalSqft * pricePerSqft };
  }, [rooms, unit, wastePct, pricePerSqft]);

  const updateRoom = (index: number, key: "length" | "width", value: number) => {
    setRooms((current) => current.map((room, roomIndex) => (roomIndex === index ? { ...room, [key]: value } : room)));
  };

  return (
    <CalculatorCard>
      <div className="grid gap-4 sm:grid-cols-2">
        <SelectField
          label="Measurement Unit"
          value={unit}
          onChange={setUnit}
          options={[
            { value: "feet", label: "Feet" },
            { value: "meters", label: "Meters" },
          ]}
        />
        <SelectField
          label="Flooring Type"
          value={flooringType}
          onChange={setFlooringType}
          options={[
            { value: "hardwood", label: "Hardwood" },
            { value: "laminate", label: "Laminate" },
            { value: "tile", label: "Tile" },
            { value: "vinyl", label: "Vinyl" },
            { value: "carpet", label: "Carpet" },
          ]}
        />
        <NumberField label="Waste Percentage" value={wastePct} onChange={setWastePct} suffix="%" />
        <NumberField label="Price Per Square Foot" value={pricePerSqft} onChange={setPricePerSqft} suffix="/sq ft" />
      </div>
      <div className="mt-5 space-y-4">
        {rooms.map((room, index) => (
          <div key={index} className="grid gap-4 rounded-2xl border border-border bg-background/60 p-4 sm:grid-cols-[1fr_1fr_auto]">
            <NumberField label={`Room ${index + 1} Length`} value={room.length} onChange={(value) => updateRoom(index, "length", value)} suffix={unit === "meters" ? "m" : "ft"} />
            <NumberField label={`Room ${index + 1} Width`} value={room.width} onChange={(value) => updateRoom(index, "width", value)} suffix={unit === "meters" ? "m" : "ft"} />
            <div className="flex items-end">
              <button
                type="button"
                onClick={() => setRooms((current) => current.filter((_, roomIndex) => roomIndex !== index))}
                disabled={rooms.length === 1}
                className="h-12 rounded-xl border border-border px-4 text-sm font-bold text-muted-foreground transition-colors hover:text-foreground disabled:cursor-not-allowed disabled:opacity-50"
              >
                Remove
              </button>
            </div>
          </div>
        ))}
        <button
          type="button"
          onClick={() => setRooms((current) => (current.length < 5 ? [...current, { length: 10, width: 10 }] : current))}
          disabled={rooms.length >= 5}
          className="rounded-xl bg-primary px-4 py-3 text-sm font-black text-white shadow-lg shadow-primary/20 transition-transform hover:-translate-y-0.5 disabled:cursor-not-allowed disabled:opacity-50"
        >
          Add Room
        </button>
      </div>
      <ResultGrid>
        <MetricCard label="Flooring Type" value={flooringType.charAt(0).toUpperCase() + flooringType.slice(1)} />
        <MetricCard label="Base Area" value={formatSqft(result.baseSqft)} />
        <MetricCard label="With Waste" value={formatSqft(result.totalSqft)} />
        <MetricCard label="Estimated Cost" value={formatCurrencyValue(result.cost)} />
      </ResultGrid>
    </CalculatorCard>
  );
}

function FenceCalculator() {
  const [perimeter, setPerimeter] = useState(150);
  const [fenceType, setFenceType] = useState("wood privacy");
  const [postSpacing, setPostSpacing] = useState(8);
  const [gateWidth, setGateWidth] = useState(4);
  const [gates, setGates] = useState(1);
  const [pricePerFoot, setPricePerFoot] = useState(25);

  const result = useMemo(() => {
    const fenceLength = Math.max(0, perimeter - gates * gateWidth);
    const sections = Math.max(1, Math.ceil(fenceLength / Math.max(1, postSpacing)));
    const posts = sections + 1 + gates * 2;
    const railRows = fenceType === "chain link" ? 1 : fenceType === "split rail" || fenceType === "aluminum" ? 2 : 3;
    const rails = sections * railRows;
    const picketsOrPanels = fenceType === "wood privacy" ? Math.ceil(fenceLength * 2) : sections;
    const concreteBags = posts * 2;
    const cost = perimeter * pricePerFoot;
    return { fenceLength, sections, posts, rails, picketsOrPanels, concreteBags, cost };
  }, [perimeter, fenceType, postSpacing, gateWidth, gates, pricePerFoot]);

  return (
    <CalculatorCard>
      <div className="grid gap-4 sm:grid-cols-2">
        <NumberField label="Total Perimeter Length" value={perimeter} onChange={setPerimeter} suffix="ft" />
        <SelectField
          label="Fence Type"
          value={fenceType}
          onChange={setFenceType}
          options={[
            { value: "wood privacy", label: "Wood Privacy" },
            { value: "chain link", label: "Chain Link" },
            { value: "split rail", label: "Split Rail" },
            { value: "vinyl", label: "Vinyl" },
            { value: "aluminum", label: "Aluminum" },
          ]}
        />
        <NumberField label="Post Spacing" value={postSpacing} onChange={setPostSpacing} suffix="ft" />
        <NumberField label="Gate Width" value={gateWidth} onChange={setGateWidth} suffix="ft" />
        <NumberField label="Number of Gates" value={gates} onChange={setGates} step="1" />
        <NumberField label="Price Per Linear Foot" value={pricePerFoot} onChange={setPricePerFoot} suffix="/ft" />
      </div>
      <ResultGrid>
        <MetricCard label="Fence Length" value={`${Math.round(result.fenceLength).toLocaleString()} ft`} helper="After gate openings" />
        <MetricCard label="Fence Posts" value={result.posts.toLocaleString()} />
        <MetricCard label="Rails" value={result.rails.toLocaleString()} />
        <MetricCard label={fenceType === "wood privacy" ? "Pickets" : "Panels or Sections"} value={result.picketsOrPanels.toLocaleString()} />
        <MetricCard label="Concrete Bags" value={result.concreteBags.toLocaleString()} />
        <MetricCard label="Estimated Cost" value={formatCurrencyValue(result.cost)} />
      </ResultGrid>
    </CalculatorCard>
  );
}

